+function isStackError(
+  value: any,
+  superJson: SuperJSON,
+  mode: 'string' | 'frames'
+): value is Error {
+  const options = superJson.errorStackOptions;
+  return (
+    isError(value) &&
+    options?.mode === mode &&
+    isErrorClassIncluded(value, options) &&
