+function isErrorClassIncluded(
+  error: Error,
+  options: NormalizedErrorStackOptions
+): boolean {
+  return !options.classFilter || options.classFilter.includes(error.name);
+}
+
+function serializeLegacyError(error: Error, superJson: SuperJSON): Record<string, any> {
+  const plain: Record<string, any> = { name: error.name, message: error.message };
+  if ('cause' in error) plain.cause = (error as any).cause;
+  superJson.allowedErrorProps.forEach(prop => {
+    plain[prop] = (error as any)[prop];
+  });
+  return plain;
+}
