+function serializeConfiguredError(error: Error, superJson: SuperJSON): Record<string, any> {
+  const options = superJson.errorStackOptions!;
+  return serializeConfiguredErrorAtDepth(error, superJson, options, 0, new Set<Error>());
+}
+
+function serializeConfiguredErrorAtDepth(
+  error: Error,
+  superJson: SuperJSON,
+  options: NormalizedErrorStackOptions,
+  depth: number,
+  seen: Set<Error>
+): Record<string, any> {
+  const allowed = superJson.allowedErrorProps;
+  const included = isErrorClassIncluded(error, options);
+  const plain: Record<string, any> = {
